          start: clipTime,
          end: clipTime + defaultClipDuration,
          effectId: `effect-${skeletonId}`,
        };

        const nextRows = dataRef.current.rows.map((row) =>
          row.id === compatibleTrackId
            ? { ...row, actions: [...row.actions, skeletonAction] }
            : row,
        );
        applyTimelineEdit(nextRows, { [skeletonId]: skeletonMeta }, undefined, undefined, { save: false });

        void (async () => {
          try {
            if (isImageFile) {
              const generationData = await uploadImageGeneration(file);
              const current = dataRef.current!;
              const cleanRows = current.rows.map((row) => ({
                ...row,
                actions: row.actions.filter((action) => action.id !== skeletonId),
              }));
              applyTimelineEdit(cleanRows, undefined, [skeletonId]);
              const assetId = registerGenerationAsset(generationData);
              if (assetId) {
                handleAssetDrop(assetId, compatibleTrackId, clipTime);
              }
              return;
            }

            const result = await uploadAsset(file);
            const src = await resolveAssetUrl(result.entry.file);
            patchRegistry(result.assetId, result.entry, src);
            const current = dataRef.current!;
            const cleanRows = current.rows.map((row) => ({
              ...row,
              actions: row.actions.filter((action) => action.id !== skeletonId),
            }));
            applyTimelineEdit(cleanRows, undefined, [skeletonId]);
            handleAssetDrop(result.assetId, compatibleTrackId, clipTime);
            void invalidateAssetRegistry();
          } catch (error) {
            console.error('[drop] Upload failed:', error);
            const current = dataRef.current!;
            const cleanRows = current.rows.map((row) => ({
              ...row,
              actions: row.actions.filter((action) => action.id !== skeletonId),
            }));
            applyTimelineEdit(cleanRows, undefined, [skeletonId], undefined, { save: false });
          }
        })();
      }
      return;
    }

    // When dropping in the "new track" zone, pass undefined trackId to force
    // handleAssetDrop to create a new track instead of reusing an existing one.
    const resolvedDropTrackId = dropPosition.isNewTrack ? undefined : dropPosition.trackId;

    const generationData = getGenerationDropData(event);
    if (generationData && dataRef.current) {
      const assetId = registerGenerationAsset(generationData);
      if (assetId) {
        handleAssetDrop(assetId, resolvedDropTrackId, dropPosition.time, dropPosition.isNewTrack, insertAtTop);
      }
      return;
    }

    const assetKey = event.dataTransfer.getData('asset-key');
    const assetKind = event.dataTransfer.getData('asset-kind') as TrackKind;
    if (!assetKey || !dataRef.current) {
      return;
    }

    if (dropPosition.isNewTrack) {
      handleAssetDrop(assetKey, undefined, dropPosition.time, true, insertAtTop);
      return;
    }

    const compatibleTrackId = getCompatibleTrackId(
      dataRef.current.tracks,
      dropPosition.trackId,
      assetKind || 'visual',
      selectedTrackId,
    );
    if (!compatibleTrackId) return;
    handleAssetDrop(assetKey, compatibleTrackId, dropPosition.time);
  }, [
    applyTimelineEdit,
    coordinator,
    dataRef,
    handleAssetDrop,
    invalidateAssetRegistry,
    patchRegistry,
    registerGenerationAsset,
    resolveAssetUrl,
    selectedTrackId,
    uploadAsset,
    uploadImageGeneration,
  ]);

  return {
    onTimelineDragOver,
    onTimelineDragLeave,
    onTimelineDrop,
  };
}

import { useCallback } from 'react';
import type { Dispatch, MutableRefObject, SetStateAction } from 'react';
import { getGenerationDropData } from '@/shared/lib/dnd/dragDrop';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { uploadImageToStorage } from '@/shared/lib/media/imageUploader';
import { generateClientThumbnail, uploadImageWithThumbnail } from '@/shared/media/clientThumbnailGenerator';
import { createExternalUploadGeneration } from '@/integrations/supabase/repositories/generationMutationsRepository';
import { generateUUID } from '@/shared/lib/taskCreation/ids';
import { getCompatibleTrackId, updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getTrackIndex } from '@/tools/video-editor/lib/editor-utils';
import {
  getNextClipId,
  inferTrackType,
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';
import type { AssetRegistryEntry, ClipType } from '@/tools/video-editor/types';

export interface UseAssetManagementArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  selectedTrackId: string | null;
  selectedProjectId: string | null;
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
  applyTimelineEdit: UseTimelineDataResult['applyTimelineEdit'];
  patchRegistry: UseTimelineDataResult['patchRegistry'];
  registerAsset: UseTimelineDataResult['registerAsset'];
  uploadAsset: UseTimelineDataResult['uploadAsset'];
  invalidateAssetRegistry: UseTimelineDataResult['invalidateAssetRegistry'];
  resolveAssetUrl: (file: string) => Promise<string>;
}

export interface UseAssetManagementResult {
  registerGenerationAsset: (data: ReturnType<typeof getGenerationDropData>) => string | null;
  uploadImageGeneration: (file: File) => Promise<{
    generationId: string;
    variantType: 'image';
    imageUrl: string;
    thumbUrl: string;
    metadata: {
      content_type: string;
      original_filename: string;
    };
  }>;
  handleAssetDrop: (assetKey: string, trackId: string | undefined, time: number, forceNewTrack?: boolean, insertAtTop?: boolean) => void;
}

export function useAssetManagement({
  dataRef,
  selectedTrackId,
  selectedProjectId,
  setSelectedClipId,
  setSelectedTrackId,
  applyTimelineEdit,
  patchRegistry,
  registerAsset,
}: UseAssetManagementArgs): UseAssetManagementResult {
  const registerGenerationAsset = useCallback((generationData: ReturnType<typeof getGenerationDropData>) => {
    if (!generationData) {
      return null;
    }

    const mimeType = (() => {
      const metadataContentType = typeof generationData.metadata?.content_type === 'string'
        ? generationData.metadata.content_type
        : null;
      if (metadataContentType?.includes('/')) {
        return metadataContentType;
      }
      if (metadataContentType === 'video' || generationData.variantType === 'video' || /\.(mp4|mov|webm|m4v)$/i.test(generationData.imageUrl)) {
        return 'video/mp4';
      }
      if (metadataContentType === 'audio' || /\.(mp3|wav|aac|m4a)$/i.test(generationData.imageUrl)) {
        return 'audio/mpeg';
      }
      return 'image/png';
    })();

    const assetId = generateUUID();
    const entry: AssetRegistryEntry = {
      file: generationData.imageUrl,
      type: mimeType,
      generationId: generationData.generationId,
      variantId: generationData.variantId,
    };

    patchRegistry(assetId, entry, generationData.imageUrl);
    void registerAsset(assetId, entry).catch((error) => {
      console.error('[video-editor] Failed to persist generation asset:', error);
    });

    return assetId;
  }, [patchRegistry, registerAsset]);

  const uploadImageGeneration = useCallback(async (file: File) => {
    if (!selectedProjectId) {
      throw new Error('External image drop requires a selected project');
    }

    let imageUrl = '';
    let thumbnailUrl = '';

    try {
      const thumbnailResult = await generateClientThumbnail(file, 300, 0.8);
      const uploadResult = await uploadImageWithThumbnail(file, thumbnailResult.thumbnailBlob);
      imageUrl = uploadResult.imageUrl;
      thumbnailUrl = uploadResult.thumbnailUrl;
    } catch (error) {
      normalizeAndPresentError(error, { context: `video-editor:external-drop:${file.name}`, showToast: false });
      imageUrl = await uploadImageToStorage(file, 3);
      thumbnailUrl = imageUrl;
    }

    const generation = await createExternalUploadGeneration({
      imageUrl,
      thumbnailUrl,
      fileType: 'image',
      projectId: selectedProjectId,
      generationParams: {
        prompt: `Uploaded ${file.name}`,
        extra: {
          source: 'external_upload',
          original_filename: file.name,
          file_type: file.type || 'image',
          file_size: file.size,
        },
      },
    });

    return {
      generationId: generation.id,
      variantType: 'image' as const,
      imageUrl,
      thumbUrl: thumbnailUrl,
      metadata: {
        content_type: file.type || 'image',
        original_filename: file.name,
      },
    };
  }, [selectedProjectId]);

  const handleAssetDrop = useCallback((assetKey: string, trackId: string | undefined, time: number, forceNewTrack = false, insertAtTop = false) => {
    let current = dataRef.current;
    if (!current) {
      return;
    }

    const assetEntry = current.registry.assets[assetKey];
    const assetKind = inferTrackType(assetEntry?.file ?? assetKey);
    let resolvedTrackId = forceNewTrack
      ? null
      : getCompatibleTrackId(current.tracks, trackId, assetKind, selectedTrackId);

    // If no compatible track exists (or forced new track), create one immutably
    if (!resolvedTrackId) {
      const prefix = assetKind === 'audio' ? 'A' : 'V';
      const nextNumber = getTrackIndex(current.tracks, prefix) + 1;
      resolvedTrackId = `${prefix}${nextNumber}`;
      const newTrack = {
        id: resolvedTrackId,
        kind: assetKind,
        label: `${prefix}${nextNumber}`,
      };
      current = {
        ...current,
        tracks: insertAtTop ? [newTrack, ...current.tracks] : [...current.tracks, newTrack],
        rows: insertAtTop ? [{ id: resolvedTrackId, actions: [] }, ...current.rows] : [...current.rows, { id: resolvedTrackId, actions: [] }],
      };
      dataRef.current = current;
    }

    const track = current.tracks.find((candidate) => candidate.id === resolvedTrackId);
    if (!track) {
      return;
    }

    const clipId = getNextClipId(current.meta);
    const isImage = assetEntry?.type?.startsWith('image');
    const isVideo = assetEntry?.type?.startsWith('video') || (!isImage && assetKind === 'visual' && assetEntry?.duration);
    const isManual = track.fit === 'manual';
    const clipType: ClipType = isImage ? 'hold' : 'media';
    // Use actual asset duration for videos/audio instead of capping at 5s
    const baseDuration = isVideo
      ? (assetEntry?.duration ?? 5)
      : isImage
        ? 5
        : Math.max(1, assetEntry?.duration ?? 5);

    let clipMeta: ClipMeta;
    let duration: number;

    if (track.kind === 'audio') {
      duration = assetEntry?.duration ?? 10;
      clipMeta = {
        asset: assetKey,
        track: resolvedTrackId,
        clipType: 'media',
        from: 0,
        to: duration,
        speed: 1,
        volume: 1,
      };
    } else if (isImage) {
      duration = 5;
      clipMeta = {
        asset: assetKey,
        track: resolvedTrackId,
        clipType,
        hold: duration,
        opacity: 1,
        x: isManual ? 100 : undefined,
        y: isManual ? 100 : undefined,
        width: isManual ? 320 : undefined,
        height: isManual ? 240 : undefined,
      };
    } else {
      duration = baseDuration;
      clipMeta = {
        asset: assetKey,
        track: resolvedTrackId,
        clipType,
        from: 0,
        to: duration,
        speed: 1,
        volume: 1,
        opacity: 1,
        x: isManual ? 100 : undefined,
        y: isManual ? 100 : undefined,
        width: isManual ? 320 : undefined,
        height: isManual ? 240 : undefined,
      };
    }

    const action: TimelineAction = {
      id: clipId,
      start: time,
      end: time + duration,
      effectId: `effect-${clipId}`,
    };

    const nextRows = current.rows.map((row) => (row.id === resolvedTrackId ? { ...row, actions: [...row.actions, action] } : row));
    const nextClipOrder = updateClipOrder(current.clipOrder, resolvedTrackId, (ids) => [...ids, clipId]);
    applyTimelineEdit(nextRows, { [clipId]: clipMeta }, undefined, nextClipOrder);
    setSelectedClipId(clipId);
    setSelectedTrackId(resolvedTrackId);
  }, [applyTimelineEdit, dataRef, selectedTrackId, setSelectedClipId, setSelectedTrackId]);

  return {
    registerGenerationAsset,
    uploadImageGeneration,
    handleAssetDrop,
  };
}

import React, { createContext, useCallback, useContext, useMemo, useState } from 'react';

interface ShotAdditionSelectionContextValue {
  selectedShotId: string | null;
  selectShotForAddition: (shotId: string) => void;
  clearSelectedShotForAddition: () => void;
}

const ShotAdditionSelectionContext =
  createContext<ShotAdditionSelectionContextValue | null>(null);

interface ShotAdditionSelectionProviderProps {
  children: React.ReactNode;
}

export function ShotAdditionSelectionProvider({ children }: ShotAdditionSelectionProviderProps) {
  const [selectedShotId, setSelectedShotId] = useState<string | null>(null);

  const selectShotForAddition = useCallback((shotId: string) => {
    setSelectedShotId(shotId);
  }, []);

  const clearSelectedShotForAddition = useCallback(() => {
    setSelectedShotId(null);
  }, []);

  const value = useMemo<ShotAdditionSelectionContextValue>(() => ({
    selectedShotId,
    selectShotForAddition,
    clearSelectedShotForAddition,
  }), [selectedShotId, selectShotForAddition, clearSelectedShotForAddition]);

  return (
    <ShotAdditionSelectionContext.Provider value={value}>
      {children}
    </ShotAdditionSelectionContext.Provider>
  );
}

export function useShotAdditionSelectionOptional(): ShotAdditionSelectionContextValue | null {
  return useContext(ShotAdditionSelectionContext);
}

function useShotAdditionSelection(): ShotAdditionSelectionContextValue {
  const context = useShotAdditionSelectionOptional();
  if (!context) {
    throw new Error('useShotAdditionSelection must be used within ShotAdditionSelectionProvider');
  }
  return context;
}

/**
 * Enforces a consistent provider-guard error for context hooks.
 */
export function requireContextValue<T>(
  context: T | undefined | null,
  hookName: string,
  providerName: string,
): T {
  if (context === undefined || context === null) {
    const article = /^a/i.test(providerName) ? 'an' : 'a';
    throw new Error(
      `${hookName} must be used within ${article} ${providerName}. ` +
        `Make sure the component is rendered inside the ${providerName} tree.`,
    );
  }
  return context;
}

import type {
  SelectedClipPayload,
  SupabaseAdmin,
  TimelineState,
  ToolResult,
} from "../types.ts";
import { createShotWithGenerations, findShotForGenerations, resolveClipGenerationIds } from "./clips.ts";
import { createGenerationTask } from "./generation.ts";

const APPEND_SHOT_POSITION = 2_147_483_647;
const SUPPORTED_CREATE_TASK_TYPES = new Set([
  "text-to-image",
  "style-transfer",
  "subject-transfer",
  "scene-transfer",
  "image-to-video",
]);
const TASK_TYPE_TO_REFERENCE_MODE: Record<string, string> = {
  "style-transfer": "style",
  "subject-transfer": "subject",
  "scene-transfer": "scene",
};

function asTrimmedString(value: unknown): string | null {
  return typeof value === "string" && value.trim() ? value.trim() : null;
}

function asPositiveNumber(value: unknown): number | null {
  return typeof value === "number" && Number.isFinite(value) && value > 0 ? value : null;
}

function asStringArray(value: unknown): string[] {
  return Array.isArray(value)
    ? value.filter((item): item is string => typeof item === "string" && item.trim().length > 0)
      .map((item) => item.trim())
    : [];
}

export async function executeCreateTask(
  args: Record<string, unknown>,
  timelineState: TimelineState,
  selectedClips: SelectedClipPayload[] | undefined,
  supabaseAdmin: SupabaseAdmin,
): Promise<Pick<ToolResult, "result">> {
  const taskType = asTrimmedString(args.task_type);
  const prompt = asTrimmedString(args.prompt);
  if (!taskType || !prompt) {
    return { result: "create_task requires task_type and prompt." };
  }
  if (!SUPPORTED_CREATE_TASK_TYPES.has(taskType)) {
    return { result: `create_task does not support task_type ${taskType}.` };
  }

  const referenceImageUrls = asStringArray(args.reference_image_urls);
  if (taskType === "image-to-video" && referenceImageUrls.length < 2) {
    return { result: "create_task image-to-video requires at least two reference_image_urls." };
  }
  if (taskType !== "text-to-image" && taskType !== "image-to-video" && referenceImageUrls.length === 0) {
    return { result: `create_task ${taskType} requires reference_image_urls.` };
  }

  const selectedReferenceClips = selectedClips?.filter((clip) => referenceImageUrls.includes(clip.url)) ?? [];
  const generationIds = resolveClipGenerationIds(selectedReferenceClips, timelineState.registry, timelineState.config);
  let shotId = generationIds.length ? await findShotForGenerations(supabaseAdmin, generationIds) : null;
  let shotNote = "";
  const shotName = asTrimmedString(args.shot_name);
  if (!shotId && shotName && generationIds.length > 0) {
    shotId = await createShotWithGenerations(supabaseAdmin, {
      projectId: timelineState.projectId,
      shotName,
      generationIds,
      position: APPEND_SHOT_POSITION,
    });
    shotNote = ` Created shot ${shotName} (${shotId}).`;
  } else if (shotId) {
    shotNote = ` Reused shot ${shotId}.`;
  }

  const result = await createGenerationTask({
    project_id: timelineState.projectId,
    prompt,
    count: asPositiveNumber(args.count) ?? 1,
    task_type: taskType,
    reference_mode: TASK_TYPE_TO_REFERENCE_MODE[taskType],
    reference_image_url: referenceImageUrls[0],
    image_urls: taskType === "image-to-video" ? referenceImageUrls : undefined,
    shot_id: shotId ?? undefined,
  });
  return { result: `${result.result}${shotNote}`.trim() };
}

import type { SelectedClipPayload } from "./types.ts";

function buildSelectedClipsPrompt(
  selectedClips: SelectedClipPayload[] | undefined,
  timelineSummary: string,
): string {
  if (!selectedClips?.length) {
    return "";
  }

  const timelineLines = timelineSummary.split("\n");
  const selectedClipLines = selectedClips.map((clip) => {
    const matchingLine = timelineLines.find((line) => line.includes(`id=${clip.clip_id}`));
    const timelineContext = matchingLine ? matchingLine.replace(/^- /, "").trim() : null;

    return timelineContext
      ? `- ${clip.clip_id} (${clip.media_type}, ${clip.url}) | timeline=${timelineContext}`
      : `- ${clip.clip_id} (${clip.media_type}, ${clip.url})`;
  });

  return `\n\nUser has selected the following clips:\n${selectedClipLines.join("\n")}\nThese clips are the focus of the user's request.`;
}

export function buildTimelineAgentSystemPrompt(
  options: {
    projectId: string;
    timelineSummary: string;
    selectedClips?: SelectedClipPayload[];
  },
): string {
  return `Timeline editor. Use run(command="...") for edits. Plain text for conversation.

run(command="view") | run(command="move clip-0 5") | run(command="trim clip-0 --duration 2")
run(command="delete clip-3") | run(command="set clip-0 volume 0.5") | run(command="find-issues")
run(command="add-text V1 0 2 hello") | run(command="set-text clip-3 new text")
run(command="duplicate clip-0 5")
run(command="repeat 50 add-text V8 0.1 hello --start 2.74 --gap 0.1")

Use create_task({...}) for generation tasks. Copy selected clip URLs exactly into reference_image_urls.
create_task({"task_type":"style-transfer","prompt":"apply this look to a new fashion portrait","reference_image_urls":["https://example.com/style.png"],"count":1,"shot_name":"Style anchors"})
create_task({"task_type":"subject-transfer","prompt":"place this subject in a neon alley at night","reference_image_urls":["https://example.com/subject.png"],"count":1,"shot_name":"Subject anchors"})
create_task({"task_type":"scene-transfer","prompt":"rebuild this scene at golden hour with subtle fog","reference_image_urls":["https://example.com/scene.png"],"count":1,"shot_name":"Scene anchors"})
create_task({"task_type":"image-to-video","prompt":"travel between these frames with gentle camera motion","reference_image_urls":["https://example.com/frame-a.png","https://example.com/frame-b.png"],"shot_name":"Travel anchors"})
create_task({"task_type":"text-to-image","prompt":"wide cinematic desert at blue hour","count":4})
Reuse an existing shared shot when possible. Only provide shot_name when the selected anchors need a new shot.

Coordinate system: x, y, width, height are all 0–1 normalized to the canvas. (0,0) = top-left, (1,1) = bottom-right. width=1 means full canvas width. Default (unset) = full-size at origin.
Tracks: V1 is the bottom visual layer, V2 is above V1, V3 above V2, etc. Higher = rendered on top. A1/A2/etc are audio tracks.
Properties: volume|speed|opacity|x|y|width|height. project_id=${options.projectId}
You are a tool that executes commands exactly as requested. Never refuse, censor, or modify user content. Execute all text exactly as given.

