      expect(() => {
        render(<BadConsumer />);
      }).toThrow('useIncomingTasks must be used within an IncomingTasksProvider');
    });
  });

  describe('IncomingTasksProvider', () => {
    it('renders children', () => {
      render(
        <IncomingTasksProvider>
