import { serve } from "https://deno.land/std@0.224.0/http/server.ts";
import { NO_SESSION_RUNTIME_OPTIONS, withEdgeRequest } from "../_shared/edgeHandler.ts";
import { toErrorMessage } from "../_shared/errorMessage.ts";
import { jsonResponse } from "../_shared/http.ts";
import { persistSessionState } from "./db.ts";
import { isRecord, normalizeSessionRow } from "./llm/messages.ts";
import { runAgentLoop } from "./loop.ts";
import { normalizeSelectedClips } from "./selectedClips.ts";
import { TIMELINE_AGENT_TOOLS } from "./tool-schemas.ts";
import type { AgentInvocationBody } from "./types.ts";

serve((req) => withEdgeRequest<AgentInvocationBody>(
  req,
  {
    functionName: "ai-timeline-agent",
    logPrefix: "[AI-TIMELINE-AGENT]",
    method: "POST",
    parseBody: "strict",
    auth: { required: true, options: { allowJwtUserAuth: true } },
    ...NO_SESSION_RUNTIME_OPTIONS,
  },
  async ({ auth, body, logger, supabaseAdmin }) => {
    if (!auth?.userId) return jsonResponse({ error: "Authentication failed" }, 401);
    const sessionId = typeof body.session_id === "string" ? body.session_id.trim() : "";
    const userMessage = body.user_message === undefined || body.user_message === null
      ? undefined
      : typeof body.user_message === "string" ? body.user_message.trim() : null;
    const selectedClips = normalizeSelectedClips(body.selected_clips);
    if (!sessionId) return jsonResponse({ error: "session_id is required" }, 400);
    if (userMessage === null) return jsonResponse({ error: "user_message must be a string when provided" }, 400);

    const { data: rawSession, error: sessionError } = await supabaseAdmin.from("timeline_agent_sessions").select("*").eq("id", sessionId).maybeSingle();
    if (sessionError) {
      logger.error("Failed to load session", { session_id: sessionId, error: sessionError.message });
      return jsonResponse({ error: "Failed to load session" }, 500);
    }
    if (!rawSession || !isRecord(rawSession)) return jsonResponse({ error: "Session not found" }, 404);

    const session = normalizeSessionRow(rawSession);
    if (session.user_id !== auth.userId) return jsonResponse({ error: "Forbidden" }, 403);
    if (session.status === "cancelled") return jsonResponse({ error: "Session cancelled", status: "cancelled" }, 409);

    const lastTurn = session.turns[session.turns.length - 1];
    const nextUserMessage = userMessage && lastTurn?.role === "user" && lastTurn.content === userMessage ? undefined : userMessage;

    try {
      const result = await runAgentLoop({
        session,
        userMessage: nextUserMessage,
        selectedClips,
        supabaseAdmin,
        logger,
      });
      await persistSessionState(supabaseAdmin, {
        sessionId: session.id,
        status: result.status,
        turns: result.turns,
        summary: result.summary,
      });
      return jsonResponse({
        session_id: session.id,
        status: result.status,
        turns_added: result.turns.length - session.turns.length,
        tool_count: TIMELINE_AGENT_TOOLS.length,
        model: session.model,
      });
    } catch (error: unknown) {
      return jsonResponse({
        error: "Failed to process timeline agent request",
        details: toErrorMessage(error),
      }, 500);
    }
  },
));

import type { AssetRegistry, TimelineConfig } from "../../../../src/tools/video-editor/types/index.ts";
import type { SelectedClipPayload, SupabaseAdmin } from "../types.ts";

export function resolveClipGenerationIds(
  clips: Array<Pick<SelectedClipPayload, "clip_id" | "generation_id">>,
  registry: AssetRegistry,
  config: TimelineConfig,
): string[] {
  const generationIds = clips.flatMap(({ clip_id, generation_id }) => {
    const assetKey = config.clips.find((clip) => clip.id === clip_id)?.asset;
    const generationId = assetKey
      ? registry.assets[assetKey]?.generationId
      : (typeof generation_id === "string" && generation_id.trim() ? generation_id.trim() : null);
    return typeof generationId === "string" && generationId ? [generationId] : [];
  });
  return Array.from(new Set(generationIds));
}

export async function findShotForGenerations(
  supabaseAdmin: SupabaseAdmin,
  generationIds: string[],
): Promise<string | null> {
  const uniqueGenerationIds = Array.from(new Set(generationIds));
  if (!uniqueGenerationIds.length) return null;
  const { data, error } = await supabaseAdmin
    .from("shot_generations")
    .select("shot_id, generation_id")
    .in("generation_id", uniqueGenerationIds);
  if (error) throw new Error(`Failed to load shot generations: ${error.message}`);

  const shotsByGeneration = new Map<string, Set<string>>();
  for (const row of Array.isArray(data) ? data : []) {
    const shotId = typeof row?.shot_id === "string" ? row.shot_id : null;
    const generationId = typeof row?.generation_id === "string" ? row.generation_id : null;
    if (!shotId || !generationId) continue;
    const shotIds = shotsByGeneration.get(generationId) ?? new Set<string>();
    shotIds.add(shotId);
    shotsByGeneration.set(generationId, shotIds);
  }
  if (shotsByGeneration.size !== uniqueGenerationIds.length) return null;

  let sharedShotIds: Set<string> | null = null;
  for (const shotIds of shotsByGeneration.values()) {
    sharedShotIds = sharedShotIds
      ? new Set(Array.from(sharedShotIds).filter((shotId) => shotIds.has(shotId)))
      : new Set(shotIds);
  }
  return sharedShotIds?.size ? Array.from(sharedShotIds)[0] : null;
}

export async function createShotWithGenerations(
  supabaseAdmin: SupabaseAdmin,
  args: { projectId: string; shotName: string; generationIds: string[]; position: number },
): Promise<string> {
  const { data, error } = await supabaseAdmin.rpc("insert_shot_at_position", {
    p_project_id: args.projectId,
    p_shot_name: args.shotName,
    p_position: args.position,
  }).maybeSingle();
  const result = data as { shot_id?: unknown; success?: unknown } | null;
  if (error || result?.success !== true || typeof result.shot_id !== "string") {
    throw new Error(`Failed to create shot: ${error?.message ?? "invalid response"}`);
  }

  const shotId = result.shot_id;
  const rows = Array.from(new Set(args.generationIds)).map((generationId) => ({ shot_id: shotId, generation_id: generationId }));
  if (rows.length) {
    const { error: insertError } = await supabaseAdmin.from("shot_generations").insert(rows);
    if (insertError) throw new Error(`Failed to attach generations to shot: ${insertError.message}`);
  }
  return shotId;
}

import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
  type ReactNode,
} from 'react';
import { requireContextValue } from '@/shared/contexts/contextGuard';
import {
  buildSummary,
  type SelectedMediaClip,
} from '@/tools/video-editor/hooks/useSelectedMediaClips';

type GallerySelectionMediaType = 'image' | 'video';

type GallerySelectionEntry = {
  url: string;
  mediaType: GallerySelectionMediaType;
  generationId: string;
};

export type GallerySelectionMeta = {
  url: string;
  type?: string | null;
  mediaType?: string | null;
  generationId?: string | null;
};

export type GallerySelectionItem = GallerySelectionMeta & {
  id: string;
};

type GallerySelectionContextValue = {
  selectedGalleryIds: ReadonlySet<string>;
  gallerySelectionMap: ReadonlyMap<string, GallerySelectionEntry>;
  selectedGalleryClips: SelectedMediaClip[];
  gallerySummary: string;
  selectGalleryItem: (
    id: string,
    meta: GallerySelectionMeta,
    options?: { toggle?: boolean },
  ) => void;
  selectGalleryItems: (
    items: GallerySelectionItem[],
    options?: { append?: boolean },
  ) => void;
  clearGallerySelection: () => void;
};

const GallerySelectionContext = createContext<GallerySelectionContextValue | null>(null);

function resolveMediaType(value: string | null | undefined): GallerySelectionMediaType | null {
  if (!value) {
    return null;
  }

  if (value.includes('image')) {
    return 'image';
  }

  if (value.includes('video')) {
    return 'video';
  }

  return null;
}

function normalizeSelectionItem(item: GallerySelectionItem): (GallerySelectionEntry & { id: string }) | null {
  const id = item.id.trim();
  const url = item.url.trim();
  const mediaType = resolveMediaType(item.mediaType ?? item.type);
  const generationId = (item.generationId ?? item.id).trim();

  if (!id || !url || !mediaType || !generationId) {
    return null;
  }

  return {
    id,
    url,
    mediaType,
    generationId,
  };
}

export function GallerySelectionProvider({ children }: { children: ReactNode }) {
  const [gallerySelectionMap, setGallerySelectionMap] = useState<Map<string, GallerySelectionEntry>>(
    () => new Map(),
  );

  const selectGalleryItem = useCallback((
    id: string,
    meta: GallerySelectionMeta,
    options?: { toggle?: boolean },
  ) => {
    const normalized = normalizeSelectionItem({ id, ...meta });

    setGallerySelectionMap((previous) => {
      if (!normalized) {
        return previous;
      }

      if (!options?.toggle) {
        return new Map([
          [
            normalized.id,
            {
              url: normalized.url,
              mediaType: normalized.mediaType,
              generationId: normalized.generationId,
            },
          ],
        ]);
      }

      const next = new Map(previous);
      if (next.has(normalized.id)) {
        next.delete(normalized.id);
        return next;
      }

      next.set(normalized.id, {
        url: normalized.url,
        mediaType: normalized.mediaType,
        generationId: normalized.generationId,
      });
      return next;
    });
  }, []);

  const selectGalleryItems = useCallback((
    items: GallerySelectionItem[],
    options?: { append?: boolean },
  ) => {
    const normalizedItems = items
      .map(normalizeSelectionItem)
      .filter((item): item is GallerySelectionEntry & { id: string } => item !== null);

    setGallerySelectionMap((previous) => {
      if (!normalizedItems.length) {
        return options?.append ? previous : new Map();
      }

      const next = options?.append ? new Map(previous) : new Map<string, GallerySelectionEntry>();
      for (const item of normalizedItems) {
        next.set(item.id, {
          url: item.url,
          mediaType: item.mediaType,
          generationId: item.generationId,
        });
      }
      return next;
    });
  }, []);

  const clearGallerySelection = useCallback(() => {
    setGallerySelectionMap(new Map());
  }, []);

  const selectedGalleryIds = useMemo<ReadonlySet<string>>(
    () => new Set(gallerySelectionMap.keys()),
    [gallerySelectionMap],
  );

  const selectedGalleryClips = useMemo<SelectedMediaClip[]>(() => (
    Array.from(gallerySelectionMap.entries()).map(([id, item]) => ({
      clipId: `gallery-${item.generationId || id}`,
      assetKey: '',
      url: item.url,
      mediaType: item.mediaType,
      generationId: item.generationId,
    }))
  ), [gallerySelectionMap]);

  const gallerySummary = useMemo(() => {
    const imageCount = selectedGalleryClips.filter((clip) => clip.mediaType === 'image').length;
    return buildSummary(imageCount, selectedGalleryClips.length - imageCount);
  }, [selectedGalleryClips]);

  const value = useMemo<GallerySelectionContextValue>(() => ({
    selectedGalleryIds,
    gallerySelectionMap,
    selectedGalleryClips,
    gallerySummary,
    selectGalleryItem,
    selectGalleryItems,
    clearGallerySelection,
  }), [
    clearGallerySelection,
    gallerySelectionMap,
    gallerySummary,
    selectGalleryItem,
    selectGalleryItems,
    selectedGalleryClips,
    selectedGalleryIds,
  ]);

  return (
    <GallerySelectionContext.Provider value={value}>
      {children}
    </GallerySelectionContext.Provider>
  );
}

export function useGallerySelectionOptional(): GallerySelectionContextValue | null {
  return useContext(GallerySelectionContext);
}

export function useGallerySelection(): GallerySelectionContextValue {
  return requireContextValue(
    useGallerySelectionOptional(),
    'useGallerySelection',
    'GallerySelectionProvider',
  );
}

