import React from 'react';
import { QueryClientProvider } from '@tanstack/react-query';
import { AuthProvider } from '@/shared/contexts/AuthContext';
import { AuthGate } from '@/shared/auth/components/AuthGate';
import { UserSettingsProvider } from '@/shared/contexts/UserSettingsContext';
import { ProjectProvider } from '@/shared/contexts/ProjectContext';
import { RealtimeProvider } from '@/shared/providers/RealtimeProvider';
import { ShotsProvider } from '@/shared/contexts/ShotsContext';
import { GenerationTaskProvider } from '@/shared/contexts/GenerationTaskContext';
import { IncomingTasksProvider } from '@/shared/contexts/IncomingTasksContext';
import { PanesProvider } from '@/shared/contexts/PanesContext';
import { LastAffectedShotProvider } from '@/shared/contexts/LastAffectedShotContext';
import { CurrentShotProvider } from '@/shared/contexts/CurrentShotContext';
import { ToolPageHeaderProvider } from '@/shared/contexts/ToolPageHeaderContext';
import { ShotAdditionSelectionProvider } from '@/shared/contexts/ShotAdditionSelectionContext';
import { TaskTypeConfigInitializer } from '@/shared/components/TaskTypeConfigInitializer';
import { TooltipProvider } from '@/shared/components/ui/tooltip';
import { queryClient } from '@/app/providers/queryClient';

interface AppProvidersProps {
  children: React.ReactNode;
}

type TreeProvider = React.ComponentType<{ children: React.ReactNode }>;

function composeProviders(providers: TreeProvider[]): TreeProvider {
  return function ProviderTree({ children }: { children: React.ReactNode }) {
    return providers.reduceRight(
      (acc, Provider) => <Provider>{acc}</Provider>,
      children
    );
  };
}

const AppProviderTree = composeProviders([
  AuthProvider,
  AuthGate,
  TaskTypeConfigInitializer,
  UserSettingsProvider,
  ProjectProvider,
  RealtimeProvider,
  ShotsProvider,
  GenerationTaskProvider,
  IncomingTasksProvider,
  PanesProvider,
  ShotAdditionSelectionProvider,
  LastAffectedShotProvider,
  CurrentShotProvider,
  ToolPageHeaderProvider,
]);

export function AppProviders({ children }: AppProvidersProps) {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider delayDuration={300}>
        <AppProviderTree>{children}</AppProviderTree>
      </TooltipProvider>
    </QueryClientProvider>
  );
}

import { useState } from 'react';
import { ChevronDown, ChevronRight, Terminal } from 'lucide-react';
import { cn } from '@/shared/components/ui/contracts/cn';
import type { AgentTurn } from '@/tools/video-editor/types/agent-session';
import type { ToolCallPair } from './AgentChat';

type AgentChatMessageProps = {
  turn: AgentTurn;
};

type AgentChatToolGroupProps = {
  pairs: ToolCallPair[];
};

function formatAttachmentSummary(attachments: AgentTurn['attachments']) {
  if (!attachments?.length) {
    return null;
  }

  const imageCount = attachments.filter((attachment) => attachment.mediaType === 'image').length;
  const videoCount = attachments.length - imageCount;
  const parts = [
    imageCount > 0 ? `${imageCount} image${imageCount === 1 ? '' : 's'}` : null,
    videoCount > 0 ? `${videoCount} video${videoCount === 1 ? '' : 's'}` : null,
  ].filter((part): part is string => part !== null);

  if (parts.length === 0) {
    return null;
  }

  return `${parts.join(', ')} attached`;
}

function formatTimestamp(timestamp: string) {
  if (!timestamp) return '';
  const date = new Date(timestamp);
  if (Number.isNaN(date.getTime())) return '';
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

export function AgentChatToolGroup({ pairs }: AgentChatToolGroupProps) {
  const [isOpen, setIsOpen] = useState(false);
  const count = pairs.length;

  // For run commands, show the command string directly
  const commandSummaries = pairs.map((p) => {
    const command = p.call.tool_args?.command;
    return typeof command === 'string' ? command : (p.call.content ?? p.call.tool_name ?? 'tool');
  });

  const label = count === 1
    ? commandSummaries[0]
    : `${count} commands`;

  return (
    <div className="w-full">
      <button
        type="button"
        className="flex w-full items-center gap-2 rounded-lg bg-muted/30 px-2.5 py-1.5 text-left text-xs transition-colors hover:bg-muted/50"
        onClick={() => setIsOpen(!isOpen)}
      >
        <Terminal className="h-3 w-3 shrink-0 text-muted-foreground" />
        <code className="flex-1 truncate font-mono text-foreground/80">{label}</code>
        {count > 1 && (isOpen ? <ChevronDown className="h-3 w-3 shrink-0 text-muted-foreground" /> : <ChevronRight className="h-3 w-3 shrink-0 text-muted-foreground" />)}
      </button>

      {isOpen && count > 1 && (
        <div className="mt-1 space-y-0.5 pl-2">
          {pairs.map((pair, index) => (
            <div key={`${pair.call.timestamp}:${index}`} className="flex items-start gap-2 rounded px-2 py-1 text-xs">
              <code className="font-mono text-foreground/70">{commandSummaries[index]}</code>
              {pair.result && (
                <span className="truncate text-muted-foreground">→ {pair.result.content?.slice(0, 80)}</span>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Show result inline for single commands */}
      {count === 1 && pairs[0].result?.content && (
        <div className="mt-0.5 px-2.5 text-xs text-muted-foreground">
          {pairs[0].result.content.slice(0, 120)}
        </div>
      )}
    </div>
  );
}

