import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Loader2, MessageSquareText, Mic, MicOff, Send, Square, X } from 'lucide-react';
import { Button } from '@/shared/components/ui/button';
import { cn } from '@/shared/components/ui/contracts/cn';
import { useGallerySelection } from '@/shared/contexts/GallerySelectionContext';
import { useAgentSession, useAgentSessions, useCancelSession, useCreateSession, useSendMessage } from '@/tools/video-editor/hooks/useAgentSession';
import {
  buildSummary,
  useSelectedMediaClips,
  type SelectedMediaClip,
} from '@/tools/video-editor/hooks/useSelectedMediaClips';
import { useAgentVoice } from '@/tools/video-editor/hooks/useAgentVoice';
import type { AgentTurn } from '@/tools/video-editor/types/agent-session';
import { AgentChatMessage, AgentChatToolGroup } from './AgentChatMessage';

type AgentChatProps = {
  timelineId: string;
};

export type ToolCallPair = {
  call: AgentTurn;
  result: AgentTurn | null;
};

export type RenderedTurn =
  | { kind: 'message'; key: string; turn: AgentTurn }
  | { kind: 'tool_group'; key: string; pairs: ToolCallPair[] };

function mergeSelectedClips(
  timelineClips: SelectedMediaClip[],
  galleryClips: SelectedMediaClip[],
): SelectedMediaClip[] {
  const clipsByUrl = new Map<string, SelectedMediaClip>();

  for (const clip of [...timelineClips, ...galleryClips]) {
    const existing = clipsByUrl.get(clip.url);
    if (!existing || (!existing.generationId && clip.generationId)) {
      clipsByUrl.set(clip.url, clip);
    }
  }

  return Array.from(clipsByUrl.values());
}

function buildRenderedTurns(turns: AgentTurn[]): RenderedTurn[] {
  const items: RenderedTurn[] = [];
  let pendingToolPairs: ToolCallPair[] = [];
  let toolGroupStartIndex = 0;

  const flushToolGroup = () => {
    if (pendingToolPairs.length === 0) return;
    items.push({
      kind: 'tool_group',
      key: `tool-group:${toolGroupStartIndex}`,
      pairs: pendingToolPairs,
    });
    pendingToolPairs = [];
  };

  for (let index = 0; index < turns.length; index += 1) {
    const turn = turns[index];

    if (turn.role === 'tool_result') {
      continue;
    }

    if (turn.role === 'tool_call') {
      const nextTurn = turns[index + 1];
      const pairedResult = nextTurn?.role === 'tool_result' ? nextTurn : null;

      if (pendingToolPairs.length === 0) {
        toolGroupStartIndex = index;
      }
      pendingToolPairs.push({ call: turn, result: pairedResult });
      if (pairedResult) index += 1;
      continue;
    }

    flushToolGroup();

    // Skip assistant messages that duplicate a preceding message_user result
    if (turn.role === 'assistant' && items.length > 0) {
      const prev = items[items.length - 1];
      if (prev.kind === 'message' && prev.turn.content === turn.content) {
        continue;
      }
    }

    items.push({
      kind: 'message',
      key: `${turn.timestamp}:${turn.role}:${index}`,
      turn,
    });
  }

  flushToolGroup();
  return items;
}

export function AgentChat({ timelineId }: AgentChatProps) {
  const sessions = useAgentSessions(timelineId);
  const createSession = useCreateSession(timelineId);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isOpen, setIsOpen] = useState(false);
  const [draft, setDraft] = useState('');
  const [optimisticMessage, setOptimisticMessage] = useState<string | null>(null);
  const hasAutoCreatedSessionRef = useRef(false);
  const bottomAnchorRef = useRef<HTMLDivElement | null>(null);
  const scrollContainerRef = useRef<HTMLDivElement | null>(null);
  const inputRef = useRef<HTMLInputElement | null>(null);

  const activeSession = useAgentSession(activeSessionId);
  const sendMessage = useSendMessage(activeSessionId, timelineId);
  const cancelSession = useCancelSession(activeSessionId);
  const sessionOptions = useMemo(() => sessions.data ?? [], [sessions.data]);
  const { clips: timelineClips } = useSelectedMediaClips();
  const {
    selectedGalleryClips,
    clearGallerySelection,
  } = useGallerySelection();
  const clips = useMemo(
    () => mergeSelectedClips(timelineClips, selectedGalleryClips),
    [selectedGalleryClips, timelineClips],
  );
  const summary = useMemo(() => {
    const imageCount = clips.filter((clip) => clip.mediaType === 'image').length;
    return buildSummary(imageCount, clips.length - imageCount);
  }, [clips]);

  const voice = useAgentVoice({
    onTranscription: (text) => {
      void handleSend(text);
    },
  });

  const renderedTurns = useMemo(
    () => buildRenderedTurns(activeSession.data?.turns ?? []),
    [activeSession.data?.turns],
  );
  const activeStatus = activeSession.data?.status;
  const isProcessing = activeStatus === 'processing' || activeStatus === 'continue';
  const showKillSwitch = activeStatus === 'processing' || activeStatus === 'continue';

  // Auto-select or create session
  useEffect(() => {
    if (!sessionOptions.length) {
      setActiveSessionId(null);
      return;
    }

    setActiveSessionId((current) => {
      if (current && sessionOptions.some((s) => s.id === current)) return current;
      return sessionOptions[0]?.id ?? null;
    });
  }, [sessionOptions]);

  // Auto-create session when needed (only when chat is open or voice is active)
  useEffect(() => {
    if (
      hasAutoCreatedSessionRef.current
      || sessions.isLoading
      || createSession.isPending
      || sessionOptions.length > 0
      || (!isOpen && !voice.isRecording && !voice.isProcessing)
    ) {
      return;
    }

    hasAutoCreatedSessionRef.current = true;
    createSession.mutate(undefined, {
      onError: () => { hasAutoCreatedSessionRef.current = false; },
      onSuccess: (session) => { setActiveSessionId(session.id); },
    });
  }, [createSession, sessionOptions.length, sessions.isLoading, isOpen, voice.isRecording, voice.isProcessing]);

  // Scroll to bottom helper
  const scrollToBottom = useCallback((smooth = true) => {
    const container = scrollContainerRef.current;
    if (!container) return;
    // Use requestAnimationFrame to ensure DOM has updated
    requestAnimationFrame(() => {
      container.scrollTo({
        top: container.scrollHeight,
        behavior: smooth ? 'smooth' : 'instant',
      });
    });
  }, []);

  // Auto-scroll on new turns or processing state change
  useEffect(() => {
    scrollToBottom();
  }, [renderedTurns, isProcessing, optimisticMessage, scrollToBottom]);

  // Scroll to bottom when opening the chat
  useEffect(() => {
    if (isOpen) {
      scrollToBottom(false);
    }
  }, [isOpen, scrollToBottom]);

  // Cmd+B global shortcut — toggle recording without opening chat
  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if ((event.metaKey || event.ctrlKey) && event.key === 'b') {
        event.preventDefault();
        if (voice.isRecording) {
          voice.stopRecording();
        } else if (!voice.isProcessing) {
          voice.startRecording();
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [voice]);

  // Focus input when opened
  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  // Clear optimistic message only when the matching turn appears in real data
  useEffect(() => {
    if (!optimisticMessage || !activeSession.data?.turns) return;
    const hasRealTurn = activeSession.data.turns.some(
      (t) => t.role === 'user' && t.content === optimisticMessage,
    );
    if (hasRealTurn) {
      setOptimisticMessage(null);
    }
  }, [activeSession.data?.turns, optimisticMessage]);

  const sendingRef = useRef(false);
  const handleSend = useCallback(async (rawText?: string) => {
    const text = (rawText ?? draft).trim();
    if (!text || !activeSessionId || sendingRef.current) return;

    const attachments = clips.map((clip) => ({
      clipId: clip.clipId,
      url: clip.url,
      mediaType: clip.mediaType,
      generationId: clip.generationId,
    }));

    if (rawText === undefined) setDraft('');
    setOptimisticMessage(text);
    sendingRef.current = true;
    try {
      await sendMessage.mutateAsync({ message: text, attachments });
      clearGallerySelection();
    } finally {
      sendingRef.current = false;
      // Don't clear optimisticMessage here — let the effect clear it
      // when the real turn arrives, avoiding a flash.
    }
  }, [activeSessionId, clearGallerySelection, clips, draft, sendMessage]);

import { useEffect, useRef, useState, type MutableRefObject } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { getSupabaseClient } from '@/integrations/supabase/client';
import type { AgentSession, AgentSessionStatus, AgentTurn } from '@/tools/video-editor/types/agent-session';
import { timelineQueryKey } from '@/tools/video-editor/hooks/useTimeline';

const TIMELINE_AGENT_SESSIONS_TABLE = 'timeline_agent_sessions';
const AUTO_CONTINUE_LIMIT = 10;
const AUTO_CONTINUE_DELAY_MS = 300;

type AgentInvocationResponse = {
  session_id: string;
  status: AgentSessionStatus;
  turns_added: number;
};

type AgentMessageAttachment = NonNullable<AgentTurn['attachments']>[number];

type SendMessageInput = {
  message: string;
  attachments?: AgentMessageAttachment[];
};

function toErrorMessage(error: unknown) {
  if (error instanceof Error) {
    return error.message;
  }

  return String(error);
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null;
}

function isAgentSessionStatus(value: unknown): value is AgentSessionStatus {
  return value === 'waiting_user'
    || value === 'processing'
    || value === 'continue'
    || value === 'done'
    || value === 'cancelled'
    || value === 'error';
}

function normalizeTurns(value: unknown): AgentTurn[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((item) => {
    if (!isRecord(item) || typeof item.content !== 'string' || typeof item.timestamp !== 'string') {
      return [];
    }

    const role = item.role;
    if (role !== 'user' && role !== 'assistant' && role !== 'tool_call' && role !== 'tool_result') {
      return [];
    }

    return [{
      role,
      content: item.content,
      attachments: Array.isArray(item.attachments) ? item.attachments : undefined,
      tool_name: typeof item.tool_name === 'string' ? item.tool_name : undefined,
      tool_args: isRecord(item.tool_args) ? item.tool_args : undefined,
      timestamp: item.timestamp,
    }];
  });
}

function normalizeSession(row: unknown): AgentSession {
  const record = isRecord(row) ? row : {};

  return {
    id: typeof record.id === 'string' ? record.id : '',
    timeline_id: typeof record.timeline_id === 'string' ? record.timeline_id : '',
    user_id: typeof record.user_id === 'string' ? record.user_id : '',
    status: isAgentSessionStatus(record.status) ? record.status : 'error',
    turns: normalizeTurns(record.turns),
    model: typeof record.model === 'string' ? record.model : 'groq',
    summary: typeof record.summary === 'string' ? record.summary : null,
    created_at: typeof record.created_at === 'string' ? record.created_at : '',
    updated_at: typeof record.updated_at === 'string' ? record.updated_at : '',
  };
}

function normalizeInvokeResponse(value: unknown): AgentInvocationResponse {
  const record = isRecord(value) ? value : {};

  return {
    session_id: typeof record.session_id === 'string' ? record.session_id : '',
    status: isAgentSessionStatus(record.status) ? record.status : 'error',
    turns_added: typeof record.turns_added === 'number' ? record.turns_added : 0,
  };
}

function delayWithTracking(timeoutIdsRef: MutableRefObject<Set<number>>, ms: number) {
  return new Promise<void>((resolve) => {
    const timeoutId = window.setTimeout(() => {
      timeoutIdsRef.current.delete(timeoutId);
      resolve();
    }, ms);
    timeoutIdsRef.current.add(timeoutId);
  });
}

export const agentSessionsQueryKey = (timelineId: string | null | undefined) =>
  ['timeline-agent-sessions', timelineId] as const;
export const agentSessionQueryKey = (sessionId: string | null | undefined) =>
  ['timeline-agent-session', sessionId] as const;

export function useAgentSessions(timelineId: string | null | undefined) {
  return useQuery({
    queryKey: agentSessionsQueryKey(timelineId),
    enabled: Boolean(timelineId),
    queryFn: async () => {
      const { data, error } = await getSupabaseClient()
        .from(TIMELINE_AGENT_SESSIONS_TABLE as never)
        .select('*')
        .eq('timeline_id', timelineId!)
        .order('updated_at', { ascending: false });

      if (error) {
        throw error;
      }

      return Array.isArray(data) ? data.map(normalizeSession) : [];
    },
  });
}

export function useAgentSession(sessionId: string | null | undefined) {
  const queryClient = useQueryClient();

  const query = useQuery({
    queryKey: agentSessionQueryKey(sessionId),
    enabled: Boolean(sessionId),
    queryFn: async () => {
      const { data, error } = await getSupabaseClient()
        .from(TIMELINE_AGENT_SESSIONS_TABLE as never)
        .select('*')
        .eq('id', sessionId!)
        .maybeSingle();

      if (error) {
        throw error;
      }

      return data ? normalizeSession(data) : null;
    },
  });

  useEffect(() => {
    if (!sessionId) {
      return;
    }

    const supabase = getSupabaseClient();
    const channel = supabase
      .channel(`timeline-agent-session:${sessionId}:${Math.random().toString(36).slice(2, 8)}`)
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'timeline_agent_sessions',
          filter: `id=eq.${sessionId}`,
        },
        () => {
          void queryClient.invalidateQueries({ queryKey: agentSessionQueryKey(sessionId) });
          void queryClient.invalidateQueries({ queryKey: ['timeline-agent-sessions'] });
        },
      )
      .subscribe((status, err) => {
        if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
          console.warn(`[useAgentSession] Realtime subscription failed (${status}), removing channel`);
          void supabase.removeChannel(channel);
        }
      });

    return () => {
      void supabase.removeChannel(channel);
    };
  }, [queryClient, sessionId]);

  return query;
}

export function useCreateSession(timelineId: string | null | undefined) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async () => {
      if (!timelineId) {
        throw new Error('timelineId is required');
      }

      const { data: authData, error: authError } = await getSupabaseClient().auth.getUser();
      if (authError) {
        throw authError;
      }

      const userId = authData.user?.id;
      if (!userId) {
        throw new Error('User not authenticated');
      }

      const { data, error } = await getSupabaseClient()
        .from(TIMELINE_AGENT_SESSIONS_TABLE as never)
        .insert({
          timeline_id: timelineId,
          user_id: userId,
          status: 'waiting_user',
          turns: [],
          model: 'groq',
        })
        .select('*')
        .single();

      if (error) {
        throw error;
      }

      return normalizeSession(data);
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: agentSessionsQueryKey(timelineId) });
    },
  });
}

export function useSendMessage(sessionId: string | null | undefined, timelineId?: string | null) {
  const queryClient = useQueryClient();
  const timeoutIdsRef = useRef<Set<number>>(new Set());
  const lastMessageRef = useRef<SendMessageInput | null>(null);
  const [continuationNotice, setContinuationNotice] = useState<string | null>(null);
  const [localError, setLocalError] = useState<string | null>(null);

  useEffect(() => {
