            <div className="flex items-center gap-2 text-red-400">
              <span className="inline-flex h-2 w-2 animate-pulse rounded-full bg-red-500" />
              Recording... {voice.remainingSeconds}s
            </div>
            <Button
              type="button"
              size="sm"
              variant="ghost"
              className="h-7 px-2 text-xs text-red-400 hover:text-red-300"
              onClick={() => voice.stopRecording()}
            >
              Done
            </Button>
          </div>
        )}

        {voice.isProcessing && (
          <div className="mb-2 flex items-center gap-2 rounded-lg bg-muted/50 px-3 py-2 text-xs text-muted-foreground">
            <Loader2 className="h-3.5 w-3.5 animate-spin" />
            Transcribing...
          </div>
        )}

        {!isProcessing && !sendMessage.isPending && (sendMessage.localError || activeStatus === 'error') && (
          <div className="mb-2 rounded-lg border border-destructive/40 bg-destructive/10 px-3 py-2 text-xs text-destructive">
            {sendMessage.localError ?? 'Agent error. Try again or start a new conversation.'}
          </div>
        )}

        <div className="flex items-center gap-2">
          <input
            ref={inputRef}
            type="text"
            value={draft}
            onChange={(event) => setDraft(event.target.value)}
            placeholder={voice.isRecording ? 'Recording...' : 'Type or press Cmd+B to talk...'}
            className="h-10 flex-1 rounded-xl border border-border/70 bg-card px-3 text-sm outline-none transition-colors placeholder:text-muted-foreground/70 focus:border-primary/50"
            disabled={!activeSessionId || isProcessing || voice.isRecording || voice.isProcessing}
            onKeyDown={(event) => {
              if (event.key === 'Enter' && !event.shiftKey) {
                event.preventDefault();
                void handleSend();
              }
            }}
          />

          <Button
            type="button"
            size="icon"
            variant={voice.isRecording ? 'destructive' : 'outline'}
            className="h-10 w-10 shrink-0 rounded-xl"
            onClick={() => voice.toggleRecording()}
            disabled={!activeSessionId || voice.isProcessing || sendMessage.isPending}
            title={voice.isRecording ? 'Stop recording' : 'Voice input (Cmd+B)'}
          >
            {voice.isRecording ? <MicOff className="h-4 w-4" /> : <Mic className="h-4 w-4" />}
          </Button>

          <Button
            type="button"
            size="icon"
            className="h-10 w-10 shrink-0 rounded-xl"
            onClick={() => void handleSend()}
            disabled={!draft.trim() || !activeSessionId || isProcessing || sendMessage.isPending}
            title="Send"
          >
            <Send className="h-4 w-4" />
          </Button>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';

type ModifierKeysState = {
  shiftKey: boolean;
  metaKey: boolean;
  ctrlKey: boolean;
  isMultiSelectModifier: boolean;
};

const EMPTY_STATE: ModifierKeysState = {
  shiftKey: false,
  metaKey: false,
  ctrlKey: false,
  isMultiSelectModifier: false,
};

export function useModifierKeys(): ModifierKeysState {
  const [state, setState] = useState<ModifierKeysState>(EMPTY_STATE);

  useEffect(() => {
    const updateState = (event: KeyboardEvent) => {
      setState({
        shiftKey: event.shiftKey,
        metaKey: event.metaKey,
        ctrlKey: event.ctrlKey,
        isMultiSelectModifier: event.shiftKey || event.metaKey || event.ctrlKey,
      });
    };

    const resetState = () => setState(EMPTY_STATE);

    window.addEventListener('keydown', updateState);
    window.addEventListener('keyup', updateState);
    window.addEventListener('blur', resetState);

    return () => {
      window.removeEventListener('keydown', updateState);
      window.removeEventListener('keyup', updateState);
      window.removeEventListener('blur', resetState);
    };
  }, []);

  return state;
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import type { GallerySelectionItem } from '@/shared/contexts/GallerySelectionContext';
import type { GeneratedImageWithMetadata } from '@/shared/components/MediaGallery/types';

type SelectionRect = {
  left: number;
  top: number;
  width: number;
  height: number;
};

type UseLassoSelectionParams = {
  containerRef: React.RefObject<HTMLElement | null>;
  items: GeneratedImageWithMetadata[];
  onSelectItems: (items: GallerySelectionItem[], options?: { append?: boolean }) => void;
};

type DragState = {
  startX: number;
  startY: number;
  append: boolean;
};

function toSelectionItem(image: GeneratedImageWithMetadata): GallerySelectionItem {
  return {
    id: image.id,
    url: image.url,
    type: image.type ?? image.contentType ?? (image.isVideo ? 'video/mp4' : 'image/png'),
    generationId: image.generation_id ?? image.id,
  };
}

function rectsIntersect(a: DOMRect, b: DOMRect) {
  return !(a.right < b.left || a.left > b.right || a.bottom < b.top || a.top > b.bottom);
}

export function useLassoSelection({
  containerRef,
  items,
  onSelectItems,
}: UseLassoSelectionParams) {
  const [selectionRect, setSelectionRect] = useState<SelectionRect | null>(null);
  const dragStateRef = useRef<DragState | null>(null);

  const itemsById = useMemo(
    () => new Map(items.map((item) => [item.id, item])),
    [items],
  );

  const endSelection = useCallback((clientX: number, clientY: number) => {
    const container = containerRef.current;
    const dragState = dragStateRef.current;

    if (!container || !dragState) {
      dragStateRef.current = null;
      setSelectionRect(null);
      return;
    }

    const normalizedRect = new DOMRect(
      Math.min(dragState.startX, clientX),
      Math.min(dragState.startY, clientY),
      Math.abs(clientX - dragState.startX),
      Math.abs(clientY - dragState.startY),
    );

    const selectedItems = Array.from(
      container.querySelectorAll<HTMLElement>('[data-gallery-item-id]'),
    ).flatMap((element) => {
      const itemId = element.dataset.galleryItemId;
      const image = itemId ? itemsById.get(itemId) : undefined;
      if (!image) {
        return [];
      }

      return rectsIntersect(normalizedRect, element.getBoundingClientRect())
        ? [toSelectionItem(image)]
        : [];
    });

    onSelectItems(selectedItems, { append: dragState.append });
    dragStateRef.current = null;
    setSelectionRect(null);
  }, [containerRef, itemsById, onSelectItems]);

  useEffect(() => {
    const handleMouseMove = (event: MouseEvent) => {
      const dragState = dragStateRef.current;
      const container = containerRef.current;
      if (!dragState || !container) {
        return;
      }

      const bounds = container.getBoundingClientRect();
      const currentX = Math.min(Math.max(event.clientX, bounds.left), bounds.right);
      const currentY = Math.min(Math.max(event.clientY, bounds.top), bounds.bottom);
      const left = Math.min(dragState.startX, currentX) - bounds.left;
      const top = Math.min(dragState.startY, currentY) - bounds.top;

      setSelectionRect({
        left,
        top,
        width: Math.abs(currentX - dragState.startX),
        height: Math.abs(currentY - dragState.startY),
      });
    };

    const handleMouseUp = (event: MouseEvent) => {
      endSelection(event.clientX, event.clientY);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [containerRef, endSelection]);

  const handleMouseDown = useCallback((event: React.MouseEvent<HTMLElement>) => {
    if (event.button !== 0) {
      return;
    }

    const container = containerRef.current;
    const target = event.target as HTMLElement;
    if (!container || target.closest('[data-gallery-item-id]')) {
      return;
    }

    const bounds = container.getBoundingClientRect();
    dragStateRef.current = {
      startX: event.clientX,
      startY: event.clientY,
      append: event.shiftKey || event.metaKey || event.ctrlKey,
    };
    setSelectionRect({
      left: event.clientX - bounds.left,
      top: event.clientY - bounds.top,
      width: 0,
      height: 0,
    });
    event.preventDefault();
  }, [containerRef]);

  return {
    selectionRect,
    handleMouseDown,
  };
}

