/**
 * Columns per row can be:
 * - 'auto': Calculate dynamically based on aspect ratio
 * - number: Fixed number of columns
 */
type ColumnsPerRow = 'auto' | number;

export interface GeneratedImageWithMetadata {
  id: string;
  /**
   * Canonical generation identity when `id` is a shot-entry ID.
   * Prefer this in cross-shot and task lookup flows.
   */
  generation_id?: string;
  /** Shot entry identity for shot_generations rows. */
  shot_generation_id?: string;
  /** Alias used by some optimistic cache paths; kept for compatibility. */
  shotImageEntryId?: string;
  url: string;
  location?: string;
  thumbUrl?: string;
  /** Stable URL identity (URL without query params) for caching/comparison - tokens change but file doesn't */
  urlIdentity?: string;
  /** Stable thumbnail URL identity for caching/comparison */
  thumbUrlIdentity?: string;
  prompt?: string;
  seed?: number;
  metadata?: DisplayableMetadata;
  temp_local_path?: string;
  error?: string;
  file?: File;
  isVideo?: boolean;
  type?: string;
  contentType?: string; // MIME type for proper download file extensions (e.g., 'video/mp4', 'image/png')
  unsaved?: boolean;
  createdAt?: string;
  updatedAt?: string | null;
  starred?: boolean;
  shot_id?: string;
  position?: number | null;
  timeline_frame?: number | null;
  name?: string; // Variant name for the generation
  primary_variant_id?: string | null;
  all_shot_associations?: Array<{ shot_id: string; position: number | null; timeline_frame?: number | null }>;
  based_on?: string | null; // ID of source generation for lineage tracking (magic edits, variations)
  derivedCount?: number; // Number of generations based on this one
  hasUnviewedVariants?: boolean; // Whether any variants have viewed_at === null (for NEW badge)
  unviewedVariantCount?: number; // Count of unviewed variants for tooltip
  // Parent/child relationship fields (for travel-between-images segments)
  is_child?: boolean;
  parent_generation_id?: string;
  child_order?: number;
}

/**
 * Canonical shot option shape used by gallery selectors and shot-jump actions.
 * Keep this surface stable so gallery/item workflows do not drift.
 */
export interface SimplifiedShotOption {
  id: string;
  name: string;
  settings?: unknown;
  created_at?: string | null;
}

/** Minimal shot navigation contract shared by gallery handlers. */
export interface NavigableShot {
  id: string;
  name?: string;
}

/**
 * Boolean config flags for MediaGallery appearance and behavior.
 * Group these into a single `config` prop to reduce top-level prop count.
 * All fields are optional — defaults are applied via `DEFAULT_GALLERY_CONFIG`.
 */
export interface GalleryConfig {
  // Visibility flags — which action buttons to show on gallery items
  showDelete: boolean;
  showDownload: boolean;
  showShare: boolean;
  showEdit: boolean;
  showStar: boolean;
  showAddToShot: boolean;

  // UI mode flags
  /** When true, single click selects (instead of opening lightbox) */
  enableSingleClick: boolean;
  /** When true, videos render as static thumbnails instead of hover-scrub */
  videosAsThumbnails: boolean;
  /** Dark surface mode - use when component is on a permanently dark surface (e.g., GenerationsPane) */
  darkSurface: boolean;
  /** Reduced spacing between gallery elements */
  reducedSpacing: boolean;
  /** Show shot filter dropdown in header */
  showShotFilter: boolean;
  /** Show search input in header */
  showSearch: boolean;

  // Hide flags — which sections to suppress
  hidePagination: boolean;
  hideTopFilters: boolean;
  hideMediaTypeFilter: boolean;
  hideBottomPagination: boolean;
  hideShotNotifier: boolean;
}

export const DEFAULT_GALLERY_CONFIG: GalleryConfig = {
  showDelete: true,
  showDownload: true,
  showShare: true,
  showEdit: false,
  showStar: true,
  showAddToShot: true,
  enableSingleClick: false,
  videosAsThumbnails: false,
  darkSurface: false,
  reducedSpacing: false,
  showShotFilter: false,
  showSearch: false,
  hidePagination: false,
  hideTopFilters: false,
  hideMediaTypeFilter: false,
  hideBottomPagination: false,
  hideShotNotifier: false,
};

interface MediaGalleryDataProps {
  images: GeneratedImageWithMetadata[];
  allShots: Shot[];
  currentToolType?: string;
  currentToolTypeName?: string;
  currentViewingShotId?: string;
  lastShotId?: string;
  lastShotNameForTooltip?: string;
  isDeleting?: string | boolean | null;
}

interface MediaGalleryActionsProps {
  onDelete?: AsyncImageDeleteHandler;
  onApplySettings?: (metadata: DisplayableMetadata | undefined) => void;
  onAddToLastShot?: AddToShotHandler;
  onAddToLastShotWithoutPosition?: AddToShotHandler;
  onToggleStar?: (id: string, starred: boolean) => void;
  onCreateShot?: (shotName: string, files: File[]) => Promise<void>;
  /** Called after delete to trigger data refetch. Should invalidate queries and refetch current page. */
  onBackfillRequest?: () => Promise<void>;
  onImageClick?: (image: GeneratedImageWithMetadata) => void;
  formAssociatedShotId?: string | null;
  onSwitchToAssociatedShot?: (shotId: string) => void;
}

interface MediaGalleryPagingProps {
  offset?: number;
  totalCount?: number;
  itemsPerPage?: number;
  onServerPageChange?: (page: number, fromBottom?: boolean) => void;
  serverPage?: number;
  enableAdjacentPagePreloading?: boolean;
}

interface MediaGalleryPaginationConfigProps {
  pagination?: MediaGalleryPagingProps;
}

interface MediaGalleryFilterProps {
  initialFilterState?: boolean;
  /** Controlled filter state — parent owns the values */
  filters?: GalleryFilterState;
  /** Callback when any filter changes (controlled mode) */
  onFiltersChange?: (filters: GalleryFilterState) => void;
  /** Default filter overrides for uncontrolled mode */
  defaultFilters?: Partial<GalleryFilterState>;
  /** Filters for generation queries - enables automatic preloading */
  generationFilters?: Record<string, unknown>;
}

interface MediaGalleryDisplayProps {
  /**
   * Number of columns per row.
   * - 'auto': Calculate dynamically based on project aspect ratio (default)
   * - number: Fixed number of columns
   */
  columnsPerRow?: ColumnsPerRow;
  /** Additional className to apply to the gallery wrapper (can override default spacing) */
  className?: string;
  /** Selection state owned by a parent wrapper such as the editor generations pane. */
  selectedIds?: ReadonlySet<string>;
  /**
   * Boolean config flags controlling gallery appearance and behavior.
   * All fields optional — unset fields use defaults from DEFAULT_GALLERY_CONFIG.
   */
  config?: Partial<GalleryConfig>;
}

export type MediaGalleryProps = MediaGalleryDataProps &
  MediaGalleryActionsProps &
  MediaGalleryPaginationConfigProps &
  MediaGalleryFilterProps &
  MediaGalleryDisplayProps;

import React from 'react';
import { MediaGallery, type GalleryFilterState } from '@/shared/components/MediaGallery';
import { useGallerySelection } from '@/shared/contexts/GallerySelectionContext';
import { SkeletonGallery } from '@/shared/components/ui/composed/skeleton-gallery';
import { useLassoSelection } from '../hooks/useLassoSelection';
import { useModifierKeys } from '../hooks/useModifierKeys';

type MediaGalleryProps = React.ComponentProps<typeof MediaGallery>;

interface GenerationsPaneLayoutModel {
  columns: number;
  itemsPerPage: number;
}

interface GenerationsPaneLoadingModel {
  isLoading: boolean;
  expectedItemCount?: number;
}

interface GenerationsPanePageModel {
  page: number;
  totalCount: number;
}

interface GenerationsPaneGalleryModel {
  items: MediaGalleryProps['images'];
  onDelete: NonNullable<MediaGalleryProps['onDelete']>;
  onToggleStar: NonNullable<MediaGalleryProps['onToggleStar']>;
  isDeleting: boolean;
  allShots: NonNullable<MediaGalleryProps['allShots']>;
  lastShotId?: string;
  filters: GalleryFilterState;
  onFiltersChange: (newFilters: GalleryFilterState) => void;
  onAddToShot: NonNullable<MediaGalleryProps['onAddToLastShot']>;
  onAddToShotWithoutPosition: NonNullable<MediaGalleryProps['onAddToLastShotWithoutPosition']>;
  onServerPageChange: NonNullable<
    NonNullable<MediaGalleryProps['pagination']>['onServerPageChange']
  >;
  generationFilters: MediaGalleryProps['generationFilters'];
  currentViewingShotId?: string;
  onCreateShot: NonNullable<MediaGalleryProps['onCreateShot']>;
}

interface GenerationsPaneGalleryProps {
  containerRef: React.RefObject<HTMLDivElement | null>;
  projectAspectRatio?: string;
  layout: GenerationsPaneLayoutModel;
  loading: GenerationsPaneLoadingModel;
  pagination: GenerationsPanePageModel;
  error: Error | null;
  gallery: GenerationsPaneGalleryModel;
}

export function GenerationsPaneGallery({
  containerRef,
  projectAspectRatio,
  layout,
  loading,
  pagination,
  error,
  gallery,
}: GenerationsPaneGalleryProps): React.ReactElement {
  const gallerySurfaceRef = React.useRef<HTMLDivElement | null>(null);
  const { selectedGalleryIds, selectGalleryItem, selectGalleryItems } = useGallerySelection();
  const modifierKeys = useModifierKeys();
  const { selectionRect, handleMouseDown } = useLassoSelection({
    containerRef: gallerySurfaceRef,
    items: gallery.items,
    onSelectItems: selectGalleryItems,
  });

  const handleImageClick = React.useCallback((image: MediaGalleryProps['images'][number]) => {
    selectGalleryItem(
      image.id,
      {
        url: image.url,
        type: image.type ?? image.contentType ?? (image.isVideo ? 'video/mp4' : 'image/png'),
        generationId: image.generation_id ?? image.id,
      },
      { toggle: modifierKeys.isMultiSelectModifier },
    );
  }, [modifierKeys.isMultiSelectModifier, selectGalleryItem]);

  return (
    <div
      ref={containerRef}
      className="flex-grow px-1 sm:px-3 overflow-y-auto overscroll-contain flex flex-col"
      style={{ WebkitOverflowScrolling: 'touch' }}
      data-tour="gallery-section"
    >
      {loading.isLoading && gallery.items.length === 0 && (
        <SkeletonGallery
          count={loading.expectedItemCount ?? layout.itemsPerPage}
          fixedColumns={layout.columns}
          gapClasses="gap-2 sm:gap-4"
          darkSurface
          showControls={false}
          projectAspectRatio={projectAspectRatio}
          className="space-y-0 pb-4 pt-2"
        />
      )}

      {error && <p className="text-red-500 text-center">Error: {error.message}</p>}

      {gallery.items.length > 0 && (
        <div className={loading.isLoading ? 'opacity-60 pointer-events-none transition-opacity duration-200' : ''}>
          <div
            ref={gallerySurfaceRef}
            className="relative"
            onMouseDown={handleMouseDown}
          >
            <MediaGallery
              images={gallery.items}
              onDelete={gallery.onDelete}
              onToggleStar={gallery.onToggleStar}
              isDeleting={gallery.isDeleting}
              allShots={gallery.allShots}
              lastShotId={gallery.lastShotId}
              filters={gallery.filters}
              onFiltersChange={gallery.onFiltersChange}
              columnsPerRow={layout.columns}
              onImageClick={handleImageClick}
              onAddToLastShot={(targetShotId, generationId, imageUrl, thumbUrl) => {
                return gallery.onAddToShot(targetShotId, generationId, imageUrl, thumbUrl);
              }}
              onAddToLastShotWithoutPosition={(targetShotId, generationId, imageUrl, thumbUrl) => {
                return gallery.onAddToShotWithoutPosition(targetShotId, generationId, imageUrl, thumbUrl);
              }}
              className="space-y-0 pb-8"
              selectedIds={selectedGalleryIds}
              config={{
                darkSurface: true,
                reducedSpacing: true,
                hidePagination: true,
                hideTopFilters: true,
                showShare: false,
                enableSingleClick: true,
              }}
              pagination={{
                offset: (pagination.page - 1) * layout.itemsPerPage,
                totalCount: pagination.totalCount,
                itemsPerPage: layout.itemsPerPage,
                serverPage: pagination.page,
                onServerPageChange: gallery.onServerPageChange,
              }}
              generationFilters={gallery.generationFilters}
              currentViewingShotId={gallery.currentViewingShotId}
              onCreateShot={gallery.onCreateShot}
            />
            {selectionRect && (
              <div
                className="pointer-events-none absolute border border-sky-400 bg-sky-400/10"
                style={{
                  left: selectionRect.left,
                  top: selectionRect.top,
                  width: selectionRect.width,
                  height: selectionRect.height,
                }}
              />
            )}
          </div>
        </div>
      )}

      {gallery.items.length === 0 && !loading.isLoading && (
        <div className="flex-1 flex items-center justify-center text-zinc-500">
          No generations found for this project.
        </div>
      )}
    </div>
  );
}

